import{_ as i}from"./chunks/god-mod-relics.BYI1kHif.js";import{_ as o,a as r}from"./chunks/god-mod-cards.BwnlzbNn.js";import{_ as l,o as d,c as n,ag as a,j as t}from"./chunks/framework.DjqkqlVQ.js";const k=JSON.parse('{"title":"STS2 God Mod","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/sts2-god-mod/index.md","filePath":"en/mods/sts2-god-mod/index.md","lastUpdated":1778777824000}'),s={name:"en/mods/sts2-god-mod/index.md"};function c(h,e,m,p,u,g){return d(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="sts2-god-mod" tabindex="-1">STS2 God Mod <a class="header-anchor" href="#sts2-god-mod" aria-label="Permalink to &quot;STS2 God Mod&quot;">​</a></h1><p>God Mod is a utility and cheat-style mod for Slay the Spire 2 designed for testing, sandbox play, build experiments, and faster run setup. It gives players and mod authors direct tools for changing game state and skipping repetitive preparation.</p><p>Current version: <code>1.6.0</code><br> Author: Jason Song<br> Type: sandbox tool / testing tool / cheat-style mod<br> Gameplay impact: yes. Use it when you intentionally want direct control over game state.</p><h2 id="highlights-in-v1-6-0" tabindex="-1">Highlights in v1.6.0 <a class="header-anchor" href="#highlights-in-v1-6-0" aria-label="Permalink to &quot;Highlights in v1.6.0&quot;">​</a></h2><ul><li>Post-combat card rewards: customize how many choices appear.</li><li>Post-combat relic rewards: can become an N-pick-1 from multiple candidates.</li><li>The resource editor is more compact: common resource fields, reward counts, campfire helpers, and Ancient-related settings are grouped to save space.</li><li>Fixed linked Ancient-style reward chains sometimes not finishing cleanup after you claim a reward.</li><li>Fixed the God (G) panel not being hideable in some cases.</li><li>Seed / RNG management (beta): includes card previews, upcoming event previews, and more.</li></ul><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><div class="screenshot-grid"><figure><img src="'+i+'" alt="God Mod relic manager"><figcaption>Relic management and quick add tools.</figcaption></figure><figure><img src="'+o+'" alt="God Mod control panel"><figcaption>G panel tool entry points.</figcaption></figure><figure><img src="'+r+'" alt="God Mod card manager"><figcaption>Card management for build testing.</figcaption></figure></div><h2 id="who-it-is-for" tabindex="-1">Who It Is For <a class="header-anchor" href="#who-it-is-for" aria-label="Permalink to &quot;Who It Is For&quot;">​</a></h2><ul><li>Players who want to test card, relic, potion, or status combinations quickly.</li><li>Mod authors who need to validate mechanics repeatedly.</li><li>Players who want to skip setup and jump into a specific experiment.</li><li>Developers debugging events, combat, map behavior, or multiplayer sync.</li></ul><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><ul><li>Edit gold, HP, max HP, energy, and potion slots.</li><li>Add or remove relics, including quick relic bundles.</li><li>Add, remove, duplicate, transform, upgrade, downgrade, enchant, keyword-edit, and stat-edit cards.</li><li>Save and apply custom deck presets.</li><li>Use built-in infinite deck presets by character.</li><li>Add, fill, or clear potions.</li><li>Apply or remove statuses in combat.</li><li>Use combat shortcuts like full heal, full energy, clear debuffs, kill all enemies, and draw/discard control.</li><li>Spawn enemies during combat.</li><li>Jump directly into events during a run.</li><li>Enable campfire tweaks such as double smith and one extra card removal per campfire.</li><li>Open the panel from the floating <code>G</code> button or the hold-<code>G</code> hotkey.</li></ul><h2 id="tool-areas" tabindex="-1">Tool Areas <a class="header-anchor" href="#tool-areas" aria-label="Permalink to &quot;Tool Areas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>What it does</th></tr></thead><tbody><tr><td>Resources</td><td>Edit gold, HP, energy, potion slots, and similar run state</td></tr><tr><td>Relics</td><td>Add, remove, and apply quick relic bundles</td></tr><tr><td>Cards</td><td>Add, duplicate, transform, upgrade, downgrade, enchant, and edit cards</td></tr><tr><td>Deck Presets</td><td>Save and reapply custom deck setups</td></tr><tr><td>Potions</td><td>Add, fill, or clear potions</td></tr><tr><td>Combat</td><td>Edit statuses, heal, refill energy, clear debuffs, kill enemies, and control draw/discard</td></tr><tr><td>Events</td><td>Jump into specific events during a run</td></tr><tr><td>Campfire</td><td>Speed up testing with double smith and extra removal helpers</td></tr></tbody></table><h2 id="opening-the-panel" tabindex="-1">Opening the Panel <a class="header-anchor" href="#opening-the-panel" aria-label="Permalink to &quot;Opening the Panel&quot;">​</a></h2><ul><li>Click the floating <code>G</code> button.</li><li>Or hold the <code>G</code> hotkey.</li></ul><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><ol><li>Download the release package.</li><li>Extract the archive.</li><li>Place the mod files into the Slay the Spire 2 mod folder: <ul><li>Windows: <code>mods/</code></li><li>macOS: <code>SlayTheSpire2.app/Contents/MacOS/mods/</code></li></ul></li><li>Launch the game and enable the mod if needed.</li></ol><h2 id="video-demo" tabindex="-1">Video Demo <a class="header-anchor" href="#video-demo" aria-label="Permalink to &quot;Video Demo&quot;">​</a></h2><p>Slay the Spire 2 God Mod Console</p>',19),t("div",{class:"video-embed"},[t("iframe",{src:"https://player.bilibili.com/player.html?bvid=BV1fJXLBuERb&page=1",title:"Slay the Spire 2 God Mod Console",scrolling:"no",border:"0",frameborder:"no",framespacing:"0",allowfullscreen:"true"})],-1),a('<h2 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h2><p>God Mod directly modifies core game state. Other mods that change gameplay, UI, debug systems, or multiplayer behavior may conflict with it.</p><p>Singleplayer testing and sandbox use are the recommended use cases. If you use it in multiplayer, only enable it in test sessions where all players agree. When reporting desyncs, disconnects, or inconsistent behavior, include the game version, God Mod version, mixed-install status, host/client details, and reproduction steps.</p><h2 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h2><p>Future updates will continue to focus on faster testing, smoother sandbox workflows, and better compatibility, including translation quality maintenance, clearer in-panel guidance, more reliable multiplayer test behavior, and easier preset and build reproduction.</p><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Quark download: <a href="https://pan.quark.cn/s/2c8c2850621d" target="_blank" rel="noreferrer">pan.quark.cn/s/2c8c2850621d</a></li><li>Nexus Mods: <a href="https://www.nexusmods.com/slaythespire2/mods/304" target="_blank" rel="noreferrer">Slay the Spire 2 Mod #304</a></li><li>Video demo: <a href="https://www.bilibili.com/video/BV1fJXLBuERb" target="_blank" rel="noreferrer">Bilibili BV1fJXLBuERb</a></li></ul><h2 id="usage-note" tabindex="-1">Usage Note <a class="header-anchor" href="#usage-note" aria-label="Permalink to &quot;Usage Note&quot;">​</a></h2><p>This mod is intended for testing and sandbox workflows. It is not a good measure of normal progression balance.</p>',9)])])}const _=l(s,[["render",c]]);export{k as __pageData,_ as default};
